using System.Security.Claims;
using Microsoft.AspNetCore.Identity;
using Microsoft.EntityFrameworkCore;
using ShipmentTracker.Client.Models;
using ShipmentTracker.Data;

namespace ShipmentTracker.Endpoints;

public static class ShipmentEndpoints
{
    public static void MapShipmentEndpoints(this WebApplication app)
    {
        var group = app.MapGroup("api/shipments");

        // Get all shipments (dispatchers only)
        group.MapGet("/", async (ApplicationDbContext db) =>
        {
            var shipments = await db.Shipments
                .OrderByDescending(s => s.CreatedAt)
                .Select(s => ToDto(s))
                .ToListAsync();
            return Results.Ok(shipments);
        }).RequireAuthorization("Dispatcher");

        // Get shipments for current customer
        group.MapGet("/my", async (ClaimsPrincipal user, ApplicationDbContext db) =>
        {
            var email = user.FindFirstValue(ClaimTypes.Email);
            if (string.IsNullOrEmpty(email))
                return Results.Ok(new List<ShipmentDto>());

            var shipments = await db.Shipments
                .Where(s => s.CustomerEmail == email)
                .OrderByDescending(s => s.CreatedAt)
                .Select(s => ToDto(s))
                .ToListAsync();
            return Results.Ok(shipments);
        }).RequireAuthorization();

        // Track by tracking number (any authenticated user)
        group.MapGet("/track/{trackingNumber}", async (string trackingNumber, ApplicationDbContext db) =>
        {
            var shipment = await db.Shipments
                .FirstOrDefaultAsync(s => s.TrackingNumber == trackingNumber);
            if (shipment is null) return Results.NotFound();
            return Results.Ok(ToDto(shipment));
        }).RequireAuthorization();

        // Create shipment (dispatchers only)
        group.MapPost("/", async (CreateShipmentRequest request, ApplicationDbContext db) =>
        {
            var shipment = new Shipment
            {
                TrackingNumber = GenerateTrackingNumber(),
                Origin = request.Origin,
                Destination = request.Destination,
                CustomerEmail = request.CustomerEmail,
                Description = request.Description,
                EstimatedDelivery = request.EstimatedDelivery,
                Status = ShipmentStatus.Pending,
                CreatedAt = DateTime.UtcNow
            };
            db.Shipments.Add(shipment);
            await db.SaveChangesAsync();
            return Results.Created($"api/shipments/{shipment.Id}", ToDto(shipment));
        }).RequireAuthorization("Dispatcher");

        // Update shipment status (dispatchers only)
        group.MapPut("/{id:int}/status", async (int id, UpdateShipmentStatusRequest request, ApplicationDbContext db) =>
        {
            var shipment = await db.Shipments.FindAsync(id);
            if (shipment is null) return Results.NotFound();
            shipment.Status = request.Status;
            await db.SaveChangesAsync();
            return Results.NoContent();
        }).RequireAuthorization("Dispatcher");
    }

    private static ShipmentDto ToDto(Shipment s) => new()
    {
        Id = s.Id,
        TrackingNumber = s.TrackingNumber,
        Origin = s.Origin,
        Destination = s.Destination,
        Status = s.Status,
        CreatedAt = s.CreatedAt,
        EstimatedDelivery = s.EstimatedDelivery,
        CustomerEmail = s.CustomerEmail,
        Description = s.Description
    };

    private static string GenerateTrackingNumber()
    {
        return $"SHP-{DateTime.UtcNow:yyyyMMdd}-{Random.Shared.Next(100000, 999999)}";
    }
}

