using System.Security.Claims;
using Microsoft.EntityFrameworkCore;
using ShipmentTracker.Client.Models;
using ShipmentTracker.Client.Services;
using ShipmentTracker.Data;

namespace ShipmentTracker;

/// <summary>
/// Server-side implementation that queries the database directly.
/// Used during interactive Server rendering before WASM takes over.
/// </summary>
public class ServerShipmentService(ApplicationDbContext db, IHttpContextAccessor httpContextAccessor) : IShipmentService
{
    public async Task<List<ShipmentDto>> GetAllShipmentsAsync()
    {
        return await db.Shipments
            .OrderByDescending(s => s.CreatedAt)
            .Select(s => new ShipmentDto
            {
                Id = s.Id,
                TrackingNumber = s.TrackingNumber,
                Origin = s.Origin,
                Destination = s.Destination,
                Status = s.Status,
                CreatedAt = s.CreatedAt,
                EstimatedDelivery = s.EstimatedDelivery,
                CustomerEmail = s.CustomerEmail,
                Description = s.Description
            })
            .ToListAsync();
    }

    public async Task<ShipmentDto?> GetShipmentByTrackingNumberAsync(string trackingNumber)
    {
        var shipment = await db.Shipments
            .FirstOrDefaultAsync(s => s.TrackingNumber == trackingNumber);
        if (shipment is null) return null;
        return ToDto(shipment);
    }

    public async Task<List<ShipmentDto>> GetMyShipmentsAsync()
    {
        var email = httpContextAccessor.HttpContext?.User.FindFirstValue(ClaimTypes.Email);
        if (string.IsNullOrEmpty(email)) return [];

        return await db.Shipments
            .Where(s => s.CustomerEmail == email)
            .OrderByDescending(s => s.CreatedAt)
            .Select(s => new ShipmentDto
            {
                Id = s.Id,
                TrackingNumber = s.TrackingNumber,
                Origin = s.Origin,
                Destination = s.Destination,
                Status = s.Status,
                CreatedAt = s.CreatedAt,
                EstimatedDelivery = s.EstimatedDelivery,
                CustomerEmail = s.CustomerEmail,
                Description = s.Description
            })
            .ToListAsync();
    }

    public async Task<ShipmentDto> CreateShipmentAsync(CreateShipmentRequest request)
    {
        var shipment = new Shipment
        {
            TrackingNumber = $"SHP-{DateTime.UtcNow:yyyyMMdd}-{Random.Shared.Next(100000, 999999)}",
            Origin = request.Origin,
            Destination = request.Destination,
            CustomerEmail = request.CustomerEmail,
            Description = request.Description,
            EstimatedDelivery = request.EstimatedDelivery,
            Status = ShipmentStatus.Pending,
            CreatedAt = DateTime.UtcNow
        };
        db.Shipments.Add(shipment);
        await db.SaveChangesAsync();
        return ToDto(shipment);
    }

    public async Task UpdateStatusAsync(int id, ShipmentStatus status)
    {
        var shipment = await db.Shipments.FindAsync(id);
        if (shipment is null) return;
        shipment.Status = status;
        await db.SaveChangesAsync();
    }

    private static ShipmentDto ToDto(Shipment s) => new()
    {
        Id = s.Id,
        TrackingNumber = s.TrackingNumber,
        Origin = s.Origin,
        Destination = s.Destination,
        Status = s.Status,
        CreatedAt = s.CreatedAt,
        EstimatedDelivery = s.EstimatedDelivery,
        CustomerEmail = s.CustomerEmail,
        Description = s.Description
    };
}

