                    <label class="form-label">Est. Delivery</label>
                    <InputDate class="form-control" @bind-Value="newShipment.EstimatedDelivery" />
                </div>
                <div class="col-md-3 d-flex align-items-end">
                    <button type="submit" class="btn btn-success w-100">Create</button>
                </div>
            </div>
        </EditForm>
    </div>
}

@if (shipments is null)
{
    <p><em>Loading shipments...</em></p>
}
else if (shipments.Count == 0)
{
    <p>No shipments found.</p>
}
else
{
    <div class="mb-3">
        <input type="text" class="form-control" placeholder="Filter by destination or tracking #..."
               @bind="filterText" @bind:event="oninput" />
    </div>

    <div class="table-responsive">
        <table class="table table-striped table-hover">
            <thead>
                <tr>
                    <th>Tracking #</th>
                    <th>Origin</th>
                    <th>Destination</th>
                    <th>Status</th>
                    <th>Customer</th>
                    <th>Est. Delivery</th>
                    <th>Actions</th>
                </tr>
            </thead>
            <tbody>
                @foreach (var shipment in FilteredShipments)
                {
                    <tr>
                        <td><code>@shipment.TrackingNumber</code></td>
                        <td>@shipment.Origin</td>
                        <td>@shipment.Destination</td>
                        <td><span class="badge bg-@GetStatusColor(shipment.Status)">@shipment.Status</span></td>
                        <td>@shipment.CustomerEmail</td>
                        <td>@shipment.EstimatedDelivery?.ToString("yyyy-MM-dd")</td>
                        <td>
                            <select class="form-select form-select-sm" value="@shipment.Status"
                                    @onchange="e => UpdateStatus(shipment, e)">
                                @foreach (var status in Enum.GetValues<ShipmentStatus>())
                                {
                                    <option value="@status">@status</option>
                                }
                            </select>
                        </td>
                    </tr>
                }
            </tbody>
        </table>
    </div>
}

@code {
    private List<ShipmentDto>? shipments;
    private CreateShipmentRequest newShipment = new();
    private bool showCreate;
    private string filterText = string.Empty;

    private IEnumerable<ShipmentDto> FilteredShipments =>
        shipments?.Where(s =>
            string.IsNullOrEmpty(filterText) ||
            s.Destination.Contains(filterText, StringComparison.OrdinalIgnoreCase) ||
            s.TrackingNumber.Contains(filterText, StringComparison.OrdinalIgnoreCase)) ?? [];

    protected override async Task OnInitializedAsync()
    {
        shipments = await ShipmentService.GetAllShipmentsAsync();
    }

    private void ShowCreateForm() => showCreate = !showCreate;

    private async Task CreateShipment()
    {
        await ShipmentService.CreateShipmentAsync(newShipment);
        newShipment = new();
        showCreate = false;
        shipments = await ShipmentService.GetAllShipmentsAsync();
    }

    private async Task UpdateStatus(ShipmentDto shipment, ChangeEventArgs e)
    {
        if (Enum.TryParse<ShipmentStatus>(e.Value?.ToString(), out var newStatus))
        {
            await ShipmentService.UpdateStatusAsync(shipment.Id, newStatus);
            shipment.Status = newStatus;
        }
    }

    private static string GetStatusColor(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "secondary",
        ShipmentStatus.PickedUp => "info",
        ShipmentStatus.InTransit => "primary",
        ShipmentStatus.OutForDelivery => "warning",
        ShipmentStatus.Delivered => "success",
        ShipmentStatus.Cancelled => "danger",
        _ => "secondary"
    };
}

@page "/tracking"
@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services
@using Microsoft.AspNetCore.Authorization
@attribute [Authorize]
@rendermode InteractiveAuto
@inject IShipmentService ShipmentService

<PageTitle>Track Shipment</PageTitle>

<h1>Track Your Shipment</h1>

<div class="row mb-4">
    <div class="col-md-6">
        <div class="input-group">
            <input type="text" class="form-control" placeholder="Enter tracking number (e.g. SHP-20260524-123456)"
                   @bind="trackingNumber" @bind:event="oninput"
                   @onkeydown="HandleKeyDown" />
            <button class="btn btn-primary" @onclick="SearchShipment">Track</button>
        </div>
    </div>
</div>

@if (searching)
{
    <p><em>Searching...</em></p>
}
else if (searchPerformed && trackedShipment is null)
{
    <div class="alert alert-warning">No shipment found with that tracking number.</div>
}
else if (trackedShipment is not null)
{
    <div class="card mb-4">
        <div class="card-header">
            <h5 class="mb-0">Shipment <code>@trackedShipment.TrackingNumber</code></h5>
        </div>
        <div class="card-body">
            <div class="row">
                <div class="col-md-6">
                    <dl>
                        <dt>Origin</dt>
                        <dd>@trackedShipment.Origin</dd>
                        <dt>Destination</dt>
                        <dd>@trackedShipment.Destination</dd>
                        <dt>Description</dt>
                        <dd>@(trackedShipment.Description ?? "—")</dd>
                    </dl>
                </div>
                <div class="col-md-6">
                    <dl>
                        <dt>Status</dt>
                        <dd><span class="badge bg-@GetStatusColor(trackedShipment.Status) fs-6">@trackedShipment.Status</span></dd>
                        <dt>Estimated Delivery</dt>
                        <dd class="fs-5 fw-bold">@(trackedShipment.EstimatedDelivery?.ToString("dddd, MMMM d, yyyy") ?? "TBD")</dd>
                        <dt>Shipped On</dt>
                        <dd>@trackedShipment.CreatedAt.ToString("yyyy-MM-dd")</dd>
                    </dl>
                </div>
            </div>

            <!-- Progress indicator -->
            <div class="mt-3">
                <h6>Shipment Progress</h6>
                <div class="progress" style="height: 30px;">
                    <div class="progress-bar bg-@GetStatusColor(trackedShipment.Status)"
                         style="width: @(GetProgress(trackedShipment.Status))%">
                        @trackedShipment.Status
                    </div>
                </div>
            </div>
        </div>
    </div>
}

<hr />

<h3>My Shipments</h3>

@if (myShipments is null)
{
    <p><em>Loading your shipments...</em></p>
}
else if (myShipments.Count == 0)
{
    <p>You have no shipments associated with your account.</p>
}
else
{
    <div class="table-responsive">
        <table class="table table-striped">
            <thead>
                <tr>
                    <th>Tracking #</th>
                    <th>Destination</th>
                    <th>Status</th>
                    <th>Est. Delivery</th>
                </tr>
            </thead>
            <tbody>
                @foreach (var s in myShipments)
                {
                    <tr class="cursor-pointer" @onclick="() => SelectShipment(s)">
                        <td><code>@s.TrackingNumber</code></td>
                        <td>@s.Destination</td>
                        <td><span class="badge bg-@GetStatusColor(s.Status)">@s.Status</span></td>
                        <td>@s.EstimatedDelivery?.ToString("yyyy-MM-dd")</td>
                    </tr>
                }
            </tbody>
        </table>
    </div>
}

@code {
    private string trackingNumber = string.Empty;
    private ShipmentDto? trackedShipment;
    private List<ShipmentDto>? myShipments;
    private bool searching;
    private bool searchPerformed;

    protected override async Task OnInitializedAsync()
    {
        myShipments = await ShipmentService.GetMyShipmentsAsync();
    }

    private async Task HandleKeyDown(Microsoft.AspNetCore.Components.Web.KeyboardEventArgs e)
    {
        if (e.Key == "Enter")
            await SearchShipment();
    }

    private async Task SearchShipment()
    {
        if (string.IsNullOrWhiteSpace(trackingNumber)) return;
        searching = true;
        searchPerformed = true;
        trackedShipment = await ShipmentService.GetShipmentByTrackingNumberAsync(trackingNumber.Trim());
        searching = false;
    }

    private void SelectShipment(ShipmentDto shipment)
    {
        trackedShipment = shipment;
        trackingNumber = shipment.TrackingNumber;
        searchPerformed = true;
    }

    private static int GetProgress(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => 10,
        ShipmentStatus.PickedUp => 30,
        ShipmentStatus.InTransit => 55,
        ShipmentStatus.OutForDelivery => 80,
        ShipmentStatus.Delivered => 100,
        ShipmentStatus.Cancelled => 100,
        _ => 0
    };

    private static string GetStatusColor(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "secondary",
        ShipmentStatus.PickedUp => "info",
        ShipmentStatus.InTransit => "primary",
        ShipmentStatus.OutForDelivery => "warning",
        ShipmentStatus.Delivered => "success",
        ShipmentStatus.Cancelled => "danger",
        _ => "secondary"
    };
}

